class Solution {
public:
    void backtrack(vector<int>& nums, int start, vector<int>& current, vector<vector<int>>& result) {
        result.push_back(current); // add current subset
        for (int i = start; i < nums.size(); i++) {
            // skip duplicates
            if (i > start && nums[i] == nums[i - 1]) continue;
            current.push_back(nums[i]);
            backtrack(nums, i + 1, current, result);
            current.pop_back();
        }
    }

    vector<vector<int>> findSubsetsWithDuplicates(vector<int>& inputNumbers) {
        vector<vector<int>> result;
        vector<int> current;
        sort(inputNumbers.begin(), inputNumbers.end()); // sort to handle duplicates
        backtrack(inputNumbers, 0, current, result);
        return result;
    }
};

