class Solution {

    public List<List<Integer>> findSubsetsWithDuplicates(int[] inputNumbers) {
        Arrays.sort(inputNumbers); // sort to handle duplicates
        List<List<Integer>> result = new ArrayList<>();
        backtrack(inputNumbers, 0, new ArrayList<>(), result);
        return result;
    }

    private void backtrack(int[] nums, int start, List<Integer> current, List<List<Integer>> result) {
        result.add(new ArrayList<>(current)); // add a copy of current subset
        for (int i = start; i < nums.length; i++) {
            if (i > start && nums[i] == nums[i - 1]) continue; // skip duplicates
            current.add(nums[i]);
            backtrack(nums, i + 1, current, result);
            current.remove(current.size() - 1);
        }
    }
}

