class Solution {
    findSubsetsWithDuplicates(inputNumbers) {
        inputNumbers.sort((a, b) => a - b); // sort to handle duplicates
        const result = [];
        const current = [];

        const backtrack = (start) => {
            result.push([...current]); // add a copy of current subset
            for (let i = start; i < inputNumbers.length; i++) {
                if (i > start && inputNumbers[i] === inputNumbers[i - 1]) continue; // skip duplicates
                current.push(inputNumbers[i]);
                backtrack(i + 1);
                current.pop();
            }
        };

        backtrack(0);
        return result;
    }
}
